Depth-First Search
In a Depth-First Search (DFS) of a graph G=(V,E) we visit a vertex v and from there we traverse, recursively, each non-visited vertex wwhich is adjacent/a successor of v. When we visit a vertex u we say the vertex is open; it remains open until the recursive traversal of all its adjacent/successors has been finished, then u gets closed.






A basic DFS implementation





#include&lt;vector&gt;
#include&lt;stack&gt;// only needed for the iterative implementation

using namespace std;

using graph = vector&lt;vector&lt;int&gt;&gt;;
using vertex = int;

void DFS_rec (const graph& G, vertex u, vector&lt;bool&gt;& visited) {
    // recursive implementation
    // DFS visit of the connected component of u in G
    if (not visited[u]) {
        visited[u] = true;
        // here we might want to "visit" u
        for (auto neighbor : G[u])
            DFS_rec(G, neighbor, visited);
    }
}

void DFS_ite (const graph& G, vertex u) {
    // iterative implementation
    // DFS visit of the connected component of u in G
    int n = G.size();
    stack&lt;int&gt; S;
    vector&lt;bool&gt; visited(n, false);
    S.push(u);
    while (not S.empty()) {
        vertex v = S.top(); 
        S.pop();
        if (not visited[v]) {
            visited[v] = true; 
            // here we might want to "visit" u
            for (auto neighbor : G[v])
                S.push(neighbor);
        } 
    } 
}









A variation of DFS to detect cycles





using namespace std;

using graph = vector&lt; vector&lt;int&gt;&gt;;
using vertex = int;

void DFS_cycles(const graph& G, vertex v, vertex father, vector&lt;bool&gt;& visited) {
    // when calling this in the main take v as father
    visited[v] = true;
    for(auto neighbor : G[v]) {
        if (not visited[neighbor]) {
            DFS_cycles(G, neighbor, v, visited);
        } else {
            if (neighbor != father) { 
                // in here we've found a cycle! 
            }
        }
    }
}



