// Forest
#include&lt;iostream&gt;
#include&lt;vector&gt;

using namespace std;
using VVI = vector&lt;vector&lt;int&gt;&gt;;
using VB = vector&lt;bool&gt;;
using VI = vector&lt;int&gt;;

bool cyclic(const VVI& g, int v, VB& visited, VI& father){
    if (visited[v]) return true;
    visited[v] = true;
    for (int u : g[v]){
        if (father[v] != u){
            father[u] = v;
            if (cyclic(g, u, visited, father)) return true;
        }
    }
    return false;
}

int count_trees(const VVI& g){
    int n = g.size();
    int n_trees = 0;
    VB visited(n, false);
    VI father(n, -1);
    for (int v = 0; v &lt; n; ++v){
        if (not visited[v]){
            if (cyclic(g, v, visited,father)) return -1;
            else ++n_trees;
        }
    }
    return n_trees;
}

int main(){
    int n, m;
